  ('pukao-e0adf6cd-moex-00287', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-110-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '依行政程序法規定，聽證程序自何時開始，於何時終結？', '["當事人提出聽證申請開始；行政機關就該事件作成決定即屬終結", "以主持人就事實或法律問題詢問當事人或其他到場人開始；待所有問答均結束後即終結", "從聽證主持人說明案由開始；待當事人充分陳述意見，事件已達可為決定之程度者，即應終結", "上級機關核准進行聽證開始；將聽證紀錄呈報上級機關時終結"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:38+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "409", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00288', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-110-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '行政程序法中有關閱覽卷宗之規定，下列何者正確？', '["任何人均得請求閱覽、抄錄行政程序有關卷宗資料", "當事人得就未給予閱覽卷宗之處置，直接提起訴願", "閱覽卷宗時如發現其中資料關於他人之記載有錯誤，得請求更正", "適用分離原則，故涉及公務機密之文書資料中，如無保密必要之部分，仍應准許閱覽"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:38+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "409", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
